/**
 * Helper: Get cards by set ID (e.g. "sc-op01", "tc-op01")
 */
function getOpZhCardsBySet(setId) {
  return OP_ZH_LIBRARY.filter(function(c) { return c.s === setId; });
}

/**
 * Helper: Get cards by language ("SC" or "TC")
 */
function getOpZhCardsByLang(lang) {
  return OP_ZH_LIBRARY.filter(function(c) { return c.l === lang; });
}

/**
 * Helper: Find a specific card by number and language
 * @param {string} cardNum - e.g. "OP01-001"
 * @param {string} lang    - "SC" or "TC" (default: "SC")
 */
function getOpZhCard(cardNum, lang) {
  lang = lang || 'SC';
  var id = 'op-' + lang.toLowerCase() + '-' + cardNum;
  return OP_ZH_LIBRARY.find(function(c) { return c.id === id; }) || null;
}

/**
 * Helper: Get all sets for a specific language
 */
function getOpZhSetsByLang(lang) {
  var result = {};
  Object.keys(OP_ZH_SETS).forEach(function(sid) {
    if (OP_ZH_SETS[sid].lang === lang) result[sid] = OP_ZH_SETS[sid];
  });
  return result;
}
